const PROM = 'http://monitoring-kube-prometheus-prometheus.monitoring.svc.cluster.local:9090/api/v1/query';

const q = async (query) => {
  const r = await $http.get({ url: PROM, qs: { query } });
  const res = r.data.data.result;
  return res.length > 0 ? parseFloat(res[0].value[1]) : 0;
};

const qAll = async (query) => {
  const r = await $http.get({ url: PROM, qs: { query } });
  return r.data.data.result;
};

// 오퍼레이터 업 상태
const upResult    = await qAll('up{job=~"operator-cnpg.*"}');
const operatorUp  = upResult.filter(r => r.value[1] === '1').length;
const operatorTotal = upResult.length;

// Reconcile 오류 합계 (controller별)
const reconcileErrors = await q('sum(controller_runtime_reconcile_errors_total{job=~"operator-cnpg.*"}) or vector(0)');

// 1시간 신규 reconcile 오류
const newReconErrors = await q('sum(increase(controller_runtime_reconcile_errors_total{job=~"operator-cnpg.*"}[1h])) or vector(0)');

// controller별 reconcile 성공 합계
const reconSuccessTotal = await q('sum(controller_runtime_reconcile_total{job=~"operator-cnpg.*",result="success"}) or vector(0)');
const reconErrorTotal   = await q('sum(controller_runtime_reconcile_total{job=~"operator-cnpg.*",result="error"}) or vector(0)');

// cluster controller 성공 (n8n-pg 포함)
const clusterReconSuccess = await q('sum(controller_runtime_reconcile_total{job=~"operator-cnpg.*",controller="cluster",result="success"}) or vector(0)');
const clusterReconError   = await q('sum(controller_runtime_reconcile_total{job=~"operator-cnpg.*",controller="cluster",result="error"}) or vector(0)');

// webhook 요청 (정상 동작 확인)
const webhookTotal = await q('sum(controller_runtime_webhook_requests_total{job=~"operator-cnpg.*"}) or vector(0)');

// 1시간 reconcile timeout
const reconTimeouts = await q('sum(increase(controller_runtime_reconcile_timeouts_total{job=~"operator-cnpg.*"}[1h])) or vector(0)');

const alerts = [];
if (operatorUp < operatorTotal) alerts.push(`🔴 오퍼레이터 Pod ${operatorTotal - operatorUp}개 다운`);
if (newReconErrors > 0)         alerts.push(`⚠️ 최근 1h Reconcile 오류: ${newReconErrors}건`);
if (reconTimeouts > 0)          alerts.push(`⚠️ 최근 1h Reconcile 타임아웃: ${reconTimeouts}건`);
if (clusterReconError > 0)      alerts.push(`🔴 Cluster 컨트롤러 오류 누적: ${clusterReconError}건`);

const status = (operatorUp < operatorTotal || clusterReconError > 0) ? 'error'
             : (newReconErrors > 0 || reconTimeouts > 0)             ? 'warning'
             : 'ok';

return [{ json: {
  service: 'CloudNativePG Operator',
  status,
  metrics: { operatorUp, operatorTotal, reconcileErrors, newReconErrors, reconSuccessTotal, reconErrorTotal, clusterReconSuccess, clusterReconError, webhookTotal, reconTimeouts },
  alerts
}}];
